NEEDS - Overview.template:
{{var "numStories" 0}}
{{var "numSatisfied" 0}}

<!-- Iterate all objects in the document 'NEEDS' and count number of stories. -->
{{#withDocument "NEEDS"}}
  {{#eachDocumentObject}}
    {{#if (eval type "==" "STORY")}}
      {{incr "numStories"}}
      {{#if (hasInlinks "satisfaction")}}
        {{incr "numSatisfied"}}
      {{/if}}
    {{/if}}
  {{/eachDocumentObject}}
{{/withDocument}}

<!-- Count number of satistied and unsatistied stories in percent. -->
{{var "numNotSatisfied" (eval (get "numStories") "-" (get "numSatisfied"))}}
{{var "percentSatisfied" 1}}
{{var "percentNotSatisfied" 0}}
{{#if (eval (get "numStories") ">" 0)}}
  {{set "percentSatisfied" (eval (get "numSatisfied") "/" (get "numStories"))}}
  {{set "percentNotSatisfied" (eval (get "numNotSatisfied") "/" (get "numStories"))}}
{{/if}}
{{var "percentSatisfied100" (round (eval (get "percentSatisfied") "*" "100"))}}
{{var "percentNotSatisfied100" (round (eval (get "percentNotSatisfied") "*" "100"))}}

<!-- HTML output section. -->

<!-- Counters -->
<div style="display: flex; flex-direction: row; flex-wrap: wrap;">
  <div style="flex: 1; min-width: 60px; padding: 4px; margin: 4px; position: relative; background-color: #f5f5f5; border: 1px solid #e3e3e3; border-radius: 4px; text-align: center; box-shadow: 3px 3px 3px grey;">
    <div style="font-size: 1.5rem">
      {{get "numStories"}}
    </div>
    <div style="white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-size: 1rem;">
      user stories
    </div>
  </div>
  <div style="flex: 1; min-width: 60px; padding: 4px; margin: 4px; position: relative; background-color: #f5f5f5; border: 1px solid #e3e3e3; border-radius: 4px; text-align: center; box-shadow: 3px 3px 3px grey;">
    <div style="font-size: 1.5rem">
      {{get "percentSatisfied100"}}%
    </div> 
    <div style="white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-size: 1rem;">
      satisfied
    </div>
  </div>
</div>

NEEDS - User Needs by Status.template:
{{var "numItems" 0}}

<!--
  Create map to count attribute value occurance and init it to 0.
  Chart will respect the order of the 'setElement' calls below.
-->
{{map "counterMap"}}
{{setElement "counterMap" "New" 0}}
{{setElement "counterMap" "Planned" 0}}
{{setElement "counterMap" "Implemented" 0}}
{{setElement "counterMap" "Verified" 0}}

<!-- Create map where labels of attribute values will be stored. -->
{{map "labelMap"}}
{{setElement "labelMap" "New" "New"}}
{{setElement "labelMap" "Planned" "Planned"}}
{{setElement "labelMap" "Implemented" "Implemented"}}
{{setElement "labelMap" "Verified" "Verified"}}

<!--
  Create theme map with color for every attribute value. Use any color syntax supported by CSS:
    - color name: 'lightblue'
    - hex RGB or RGBA: '#add8e6' or '#add8e6ff'
    - decimal RGB or RGBA: 'rgb(173, 216, 230)' or 'rgba(173, 216, 230, 1.)'
    - other syntaxes, see https://developer.mozilla.org/en-US/docs/Web/CSS/named-color
-->
{{map "colorMap"}}
{{setElement "colorMap" "New" "khaki"}}
{{setElement "colorMap" "Planned" "sandybrown"}}
{{setElement "colorMap" "Implemented" "lightblue"}}
{{setElement "colorMap" "Verified" "lightgreen"}}

<!-- Iterate all objects in the document 'NEEDS' and count occurance of attribute value(s). -->
{{#withDocument "NEEDS" tableView="Filter User Stories"}}
  {{#eachDocumentObject}}
    {{incr "numItems"}}
    {{#if (attributeEnumKey "status")}}
      {{#if (includes "counterMap" (attributeEnumKey "status"))}}
        {{setElement "counterMap" (attributeEnumKey "status") (eval (getElement "counterMap" (attributeEnumKey "status")) "+" 1)}}
      {{/if}}
    {{/if}}
  {{/eachDocumentObject}}
{{/withDocument}}

<!-- Find maximum value for to convert values into normalize range [0..1] in HTML output section. -->
{{var "maxValue" 0}}
{{#eachOfMap "counterMap"}}
  {{#if (eval @value ">" (get "maxValue"))}}
    {{set "maxValue" @value}}
  {{/if}}
{{/eachOfMap}}

<!-- Chart -->
<div style="container-type: size; width: 100%; height: 100%; font-size: 0.9em;">
  <table class="charts-css show-primary-axis data-outside column data-spacing-4 show-labels" style="min-width: 50px; height: 100%;">
    <thead>
      <tr>
        <th>Status</th>
        <th>Count</th>
      </tr>
    </thead>
    <tbody style="height: inherit;">
{{#eachOfMap "counterMap"}}
      <tr>
        <th style="text-overflow: ellipsis; overflow: hidden; white-space: nowrap;">{{{getElement "labelMap" @key}}}</th>
        <td style="--size: {{eval @value "/" (get "maxValue")}}; background: {{getElement "colorMap" @key}};">
          <span class="data" style="white-space: nowrap;">{{@value}}</span>
          <span class="tooltip">{{@value}} of {{get "numItems"}}</span>
        </td>
      </tr>
{{/eachOfMap}}
    </tbody>
  </table>
</div>

